import { NextRequest, NextResponse } from 'next/server';
import OpenAI from 'openai';
import { SYSTEM_PROMPT, REFINEMENT_PROMPT } from '@/lib/logo-generator/prompts';

const openai = new OpenAI({
    apiKey: process.env.OPENAI_API_KEY,
});

// In-memory conversation storage (use database in production)
const conversations = new Map<string, Array<{ role: string; content: string }>>();

export async function POST(request: NextRequest) {
    try {
        const { conversationId, selections } = await request.json();

        // Get or initialize conversation history
        let history = conversations.get(conversationId) || [];

        // Add user selections to history
        history.push({
            role: 'user',
            content: `Selected: ${selections.join(', ')}`,
        });

        // Call OpenAI for refinement
        const completion = await openai.chat.completions.create({
            model: 'gpt-4o',
            messages: [
                {
                    role: 'system',
                    content: SYSTEM_PROMPT,
                },
                ...history.map((msg) => ({
                    role: msg.role as 'user' | 'assistant',
                    content: msg.content,
                })),
                {
                    role: 'user',
                    content: REFINEMENT_PROMPT(history, selections),
                },
            ],
            response_format: { type: 'json_object' },
            temperature: 0.7,
        });

        const response = JSON.parse(completion.choices[0].message.content || '{}');

        // Update conversation history
        history.push({
            role: 'assistant',
            content: response.explanation || 'Logo refined based on your preferences.',
        });
        conversations.set(conversationId, history);

        return NextResponse.json({
            svg: response.svg,
            message: response.explanation,
            options: response.question?.options,
        });
    } catch (error) {
        console.error('Error refining logo:', error);
        return NextResponse.json(
            { error: 'Failed to refine logo' },
            { status: 500 }
        );
    }
}
